            CREATE OR REPLACE FUNCTION sync_module_item_to_item()
            RETURNS TRIGGER AS $$
            BEGIN
                IF (TG_OP = 'INSERT') THEN
                    INSERT INTO item (
                        item_id, name, description, units, item_data_type_id, oc_oid,
                        phi_status, status_id, owner_id, date_created, date_updated, update_id
                    )
                    VALUES (
                        NEW.item_id, NEW.name, NEW.description, NEW.units, NEW.item_data_type_id, NEW.oc_oid,
                        NEW.phi_status, NEW.status_id, NEW.owner_id, NEW.date_created, NEW.date_updated, NEW.update_id
                    );
                    RETURN NEW;
                ELSIF (TG_OP = 'UPDATE') THEN
                    UPDATE item SET
                        name = NEW.name,
                        description = NEW.description,
                        units = NEW.units,
                        item_data_type_id = NEW.item_data_type_id,
                        oc_oid = NEW.oc_oid,
                        phi_status = NEW.phi_status,
                        status_id = NEW.status_id,
                        owner_id = NEW.owner_id,
                        date_created = NEW.date_created,
                        date_updated = NEW.date_updated,
                        update_id = NEW.update_id
                    WHERE item_id = OLD.item_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'DELETE') THEN
                    DELETE FROM item WHERE item_id = OLD.item_id;
                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            CREATE TRIGGER trg_sync_module_item
            AFTER INSERT OR UPDATE OR DELETE ON module_item
            FOR EACH ROW EXECUTE FUNCTION sync_module_item_to_item();
